from typing import Callable, Dict, List


class EventEmitter:
    """
    A simple event emitter that allows registering handlers for events
    and emitting events to call all registered handlers in order.
    """

    def __init__(self):
        self._handlers: Dict[str, List[Callable]] = {}

    def on(self, event: str, handler: Callable) -> None:
        """
        Register a handler for an event.

        Args:
            event: The event name
            handler: A callable to invoke when the event is emitted
        """
        if event not in self._handlers:
            self._handlers[event] = []
        self._handlers[event].append(handler)

    def off(self, event: str, handler: Callable) -> None:
        """
        Unregister a handler from an event.

        Args:
            event: The event name
            handler: The callable to remove
        """
        if event in self._handlers:
            try:
                self._handlers[event].remove(handler)
            except ValueError:
                pass  # Handler not found, silently ignore

