def insert_position(sorted_list, value):
    """Return the leftmost index at which `value` can be inserted into
    `sorted_list` to keep it sorted. Binary search, O(log n)."""
    lo, hi = 0, len(sorted_list)
    while lo < hi:
        mid = (lo + hi) // 2
        if sorted_list[mid] < value:
            lo = mid + 1
        else:
            hi = mid
    return lo
